const items = $input.all();
const companies = [];
const seen = new Set();

for (const item of items) {
  let html = '';
  if (typeof item.json === 'string') {
    html = item.json;
  } else if (item.json.data) {
    html = item.json.data;
  } else {
    html = JSON.stringify(item.json);
  }

  // Extract company names from <h3 tags using regex
  const h3Matches = html.match(/<h3[^>]*>([^<]{2,80})<\/h3>/gi) || [];

  // Also try company name JSON-LD or meta patterns
  const jsonLdMatches = html.match(/\"name\":\s*\"([^\"]{3,80})\"/g) || [];

  for (const match of h3Matches) {
    // Strip HTML tags and decode entities
    const name = match
      .replace(/<[^>]+>/g, '')
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&#[0-9]+;/g, '')
      .trim();

    if (!name || name.length < 2 || seen.has(name)) continue;
    // Filter out nav/UI elements
    if (/^(Home|About|Contact|Login|Sign|Menu|Search|Filter|Sort|Next|Prev|Load)/i.test(name)) continue;

    seen.add(name);
    companies.push({
      json: {
        Company: name,
        Website: 'Unknown',
        Careers_URL: 'Unknown',
        Country: 'Europe',
        City: 'Unknown',
        Sector: 'Technology',
        Subsector: 'Startup',
        Company_Stage: 'Startup',
        Company_Scale: 'Unknown',
        Employer_Category: 'EU Startup',
        Remote: 'Unknown',
        Visa_Sponsorship: 'Unknown',
        EOR: 'Unknown',
        Hiring_Geography: 'EU',
        Target_Roles: 'Data Engineer, AI/ML Engineer',
        Tech_Stack: 'Unknown',
        Region_Eligibility: 'EU',
        Portfolio_Theme_Match: 'Unknown',
        Language_Requirement: 'English',
        Hiring_Confidence: 'Low',
        Reason_Match: 'EU startup listed in eu-startups.com directory',
        Source: 'eu-startups.com directory',
        Cold_Outreach_Candidate: 'Yes',
        Visa_Sponsor_Register: 'Unknown'
      }
    });
  }
}

if (companies.length === 0) {
  return [{ json: { message: 'No companies parsed from EU Startups directory', note: 'Page may require JS rendering' } }];
}

return companies;
